// ============================================================
// Node-RED Function node: B Meters Hydrodigit S1 decoder
// Gebaseerd op B Meters LoRaWAN spec v1.5
// Ondersteunt: Standard uplink (v003 & v004+) + Datalogger uplink
// ============================================================

const Dev = "ASSET" // <-- jouw asset ID

const ID_VOLUME_M3 = 5000
const ID_REVERSE_M3 = 5050
const ID_TEMPERATURE = 6800
const ID_ALARM_LEAKAGE = 5055
const ID_ALARM_BURST = 5060
const ID_ALARM_OVERFLOW = 5065
const ID_RSSI = 5500
const ID_SNR = 5400
const ID_SF = 5200

function toBytes(input) {
    if (Buffer.isBuffer(input)) return Array.from(input)
    if (typeof input === 'string') {
        const hexClean = input.replace(/\s+/g, '')
        if (/^[0-9a-fA-F]+$/.test(hexClean) && hexClean.length % 2 === 0) {
            const r = []
            for (let i = 0; i < hexClean.length; i += 2)
                r.push(parseInt(hexClean.substr(i, 2), 16))
            return r
        }
        return Array.from(Buffer.from(input, 'base64'))
    }
    if (Array.isArray(input)) return input
    throw new Error("Onbekend payload formaat")
}

function readUInt32LE(b, o) {
    return ((b[o] | b[o + 1] << 8 | b[o + 2] << 16 | b[o + 3] << 24) >>> 0)
}

function readUInt16LE(b, o) {
    return (b[o] | b[o + 1] << 8) >>> 0
}

function epochToISO(epoch) {
    return new Date((epoch + 946684800) * 1000).toISOString()
}

function decodeTemp(msb, lsb) {
    let raw = (msb << 8) | lsb
    if (raw & 0x8000) raw = raw - 0x10000
    return parseFloat((raw / 10).toFixed(1))
}

function decodeVolume(b, offset) {
    const msNibble = (b[offset + 3] >> 4) & 0x0F
    return (msNibble << 24) | (b[offset + 2] << 16) | (b[offset + 1] << 8) | b[offset]
}

function decodeReverseFlow(b, nibbleOffset) {
    const msNibble = b[nibbleOffset] & 0x0F
    return (msNibble << 24) | (b[nibbleOffset + 3] << 16) | (b[nibbleOffset + 2] << 8) | b[nibbleOffset + 1]
}

function decodeAlarms(kk) {
    return {
        leakage: !!(kk & 0x01),
        overflow: !!(kk & 0x04),
        burst: !!(kk & 0x08)
    }
}

function decodeStandard(b, version) {
    const volumeLiter = decodeVolume(b, 1)
    const reverseLiter = decodeReverseFlow(b, 4)
    const alarmByte = version === '004+' ? b[8] : b[7]
    const alarms = decodeAlarms(alarmByte)
    const result = {
        type: 'standard',
        version: version,
        volume_m3: parseFloat((volumeLiter / 1000).toFixed(3)),
        reverse_m3: parseFloat((reverseLiter / 1000).toFixed(3)),
        alarms: alarms
    }
    const tempOffset = version === '004+' ? 9 : 8
    if (b.length >= tempOffset + 2) {
        result.temperature_c = decodeTemp(b[tempOffset], b[tempOffset + 1])
    }
    return result
}

function decodeDatalogger(b, version) {
    const currentVolume = readUInt32LE(b, 1)
    const currentEpoch = readUInt32LE(b, 5)
    const lastLogVolume = readUInt32LE(b, 9)
    const lastLogEpoch = readUInt32LE(b, 13)
    const deltas = []
    for (let i = 0; i < 14; i++) {
        let raw = readUInt16LE(b, 17 + i * 2)
        if (raw & 0x8000) raw = raw - 0x10000
        deltas.push(raw)
    }
    const result = {
        type: 'datalogger',
        version: version,
        volume_m3: parseFloat((currentVolume / 1000).toFixed(3)),
        timestamp: epochToISO(currentEpoch),
        last_log_volume_m3: parseFloat((lastLogVolume / 1000).toFixed(3)),
        last_log_timestamp: epochToISO(lastLogEpoch),
        hourly_deltas_l: deltas,
        alarms: decodeAlarms(b[45])
    }
    if (b.length >= 48) {
        result.temperature_c = decodeTemp(b[46], b[47])
    }
    return result
}

try {
    const rawPayload = msg.payload.data || msg.payload
    const b = toBytes(rawPayload)
    const appCode = b[0]

    if (appCode !== 0x45 && appCode !== 0x50)
        throw new Error("Onbekende application code: 0x" + appCode.toString(16).toUpperCase())

    const version = appCode === 0x50 ? '004+' : '003'

    // Datalogger heeft exact 45+ bytes, standard is kleiner
    const isDatalogger = b.length >= 45 && b.length !== 9 && b.length !== 11
    const data = isDatalogger
        ? decodeDatalogger(b, version)
        : decodeStandard(b, version)

    const MD = []
    MD.push({ Id: ID_VOLUME_M3, Val: data.volume_m3 })
    MD.push({ Id: ID_REVERSE_M3, Val: data.reverse_m3 !== undefined ? data.reverse_m3 : 0 })

    if (data.temperature_c !== undefined)
        MD.push({ Id: ID_TEMPERATURE, Val: data.temperature_c })

    if (data.alarms) {
        MD.push({ Id: ID_ALARM_LEAKAGE, Val: data.alarms.leakage ? 1 : 0 })
        MD.push({ Id: ID_ALARM_OVERFLOW, Val: data.alarms.overflow ? 1 : 0 })
        MD.push({ Id: ID_ALARM_BURST, Val: data.alarms.burst ? 1 : 0 })
    }

    // Gecorrigeerde paden — consistent met andere decoders
    if (msg.rssi !== undefined)
        MD.push({ Id: ID_RSSI, Val: parseFloat(msg.rssi) })
    if (msg.snr !== undefined)
        MD.push({ Id: ID_SNR, Val: parseFloat(msg.snr) })
    if (msg.dr?.spreadFactor !== undefined)
        MD.push({ Id: ID_SF, Val: parseFloat(msg.dr.spreadFactor) })

    const mid = global.get("mid") || 0
    global.set("mid", mid + 1)

    msg.payload = {
        MID: mid,
        D: [{
            Dev: Dev,
            ED: [],
            MD: MD,
            TS: msg.time ? new Date(msg.time).toISOString() : new Date().toISOString()
        }]
    }

    return msg

} catch (err) {
    node.error("W_BME_HYDRO_LORA_V1 decoder fout: " + err.message, msg)
    return null
}
